// =============================================================
// API 키 인증 및 입력 검증
// 감정 분석 워크플로우 진입점
// =============================================================

const headers = $input.first().json.headers || {};
const body    = $input.first().json.body || {};

// API 키 인증
let expectedApiKey;
try { expectedApiKey = $env.API_SECRET_KEY; } catch(e) {}
expectedApiKey = expectedApiKey || 'n8n-ollama-api-key-2024';
const providedApiKey = headers['x-api-key'] || headers['X-API-Key'] || '';

if (providedApiKey !== expectedApiKey) {
  throw new Error('AUTH_FAILED: 유효하지 않은 API 키입니다.');
}

const userMessage = (body.message || '').trim();
const sessionId   = body.session_id || `sentiment_${Date.now()}`;

if (!userMessage) {
  throw new Error('VALIDATION_ERROR: message 필드는 필수입니다.');
}

const requestStartTime = Date.now();
const requestId = `sent_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;

const sentimentSystemPrompt = [
  '당신은 감정 분석 전문가입니다. 반드시 한국어로만 응답하세요.',
  '사용자의 메시지를 분석하여 반드시 아래 JSON 형식으로만 응답하세요.',
  '다른 텍스트는 절대 포함하지 마세요.',
  '',
  '응답 형식:',
  '{"sentiment": "positive" | "negative" | "neutral", "confidence": 0.0~1.0, "reason": "감정 판단 근거 한 문장 (반드시 한국어)", "emotions": ["한국어감정1", "한국어감정2"]}'
].join('\n');

const sentimentBody = {
  model: 'exaone3.5:2.4b',
  messages: [
    { role: 'system', content: sentimentSystemPrompt },
    { role: 'user', content: '다음 메시지의 감정을 분석해주세요: "' + userMessage + '"' }
  ],
  stream: false,
  options: { temperature: 0.3, num_predict: 256 }
};

return { userMessage, sessionId, requestStartTime, requestId, sentimentBody };

// =============================================================
// 감정 분석 결과 파싱
// LLM 응답에서 JSON을 추출하고 감정에 따른 톤 결정
// =============================================================

const llmResponse = $input.first().json;
const authData    = $('인증 및 검증').first().json;

// LLM 응답에서 감정 분석 JSON 추출
let sentimentData = {
  sentiment:  'neutral',
  confidence: 0.5,
  reason:     '분석 결과를 파싱하는 데 실패했습니다.',
  emotions:   []
};

try {
  const rawContent = llmResponse?.message?.content || llmResponse?.response || '{}';
  // JSON 블록 추출 (마크다운 코드 블록 제거)
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    sentimentData = {
      sentiment:  parsed.sentiment  || 'neutral',
      confidence: parseFloat(parsed.confidence) || 0.5,
      reason:     parsed.reason     || '감정을 분석했습니다.',
      emotions:   Array.isArray(parsed.emotions) ? parsed.emotions : []
    };
  }
} catch (e) {
  // 파싱 실패 시 기본값 유지
}

// 감정이 유효한 값인지 확인
const validSentiments = ['positive', 'negative', 'neutral'];
if (!validSentiments.includes(sentimentData.sentiment)) {
  sentimentData.sentiment = 'neutral';
}

// -------------------------------------------------------
// 감정에 따른 응답 톤 결정
// -------------------------------------------------------
const toneMap = {
  positive: {
    name:         '열정적 톤',
    systemPrompt: '당신은 열정적이고 긍정적인 AI 어시스턴트입니다. 반드시 한국어로만 응답하세요. 사용자의 긍정적인 에너지에 공감하며, 활기차고 격려하는 방식으로 응답하세요. 이모티콘을 적절히 사용하고, 사용자의 성공과 행복을 응원하는 톤을 유지하세요.'
  },
  negative: {
    name:         '공감적 톤',
    systemPrompt: '당신은 공감 능력이 뛰어난 AI 어시스턴트입니다. 반드시 한국어로만 응답하세요. 사용자의 감정을 먼저 인정하고 이해하세요. 판단하지 않고 지지하는 방식으로 응답하며, 필요한 경우 실질적인 도움을 제안하세요. 차분하고 따뜻한 톤을 유지하세요.'
  },
  neutral: {
    name:         '정보 제공 톤',
    systemPrompt: '당신은 명확하고 유익한 정보를 제공하는 AI 어시스턴트입니다. 반드시 한국어로만 응답하세요. 객관적이고 구조적인 방식으로 응답하며, 사실에 기반한 정보를 제공하세요. 중립적이고 전문적인 톤을 유지하세요.'
  }
};

const selectedTone = toneMap[sentimentData.sentiment];

const toneBody = {
  model: 'exaone3.5:2.4b',
  messages: [
    { role: 'system', content: selectedTone.systemPrompt },
    { role: 'user', content: authData.userMessage }
  ],
  stream: false,
  options: { temperature: 0.8, top_p: 0.9, num_predict: 768 }
};

return {
  toneBody,
  ...authData,
  sentimentData,
  selectedTone
};

// =============================================================
// 최종 응답 조합 및 PostgreSQL 저장 데이터 준비
// =============================================================

const toneResponse  = $input.first().json;
const sentimentData = $('감정 파싱 및 톤 선택').first().json;

// 최종 AI 응답 추출
const aiMessage    = toneResponse?.message?.content || toneResponse?.response || '응답 생성 실패';
const modelUsed    = toneResponse?.model || 'exaone3.5:2.4b';
const responseTime = Date.now() - sentimentData.requestStartTime;

return {
  requestId:    sentimentData.requestId,
  sessionId:    sentimentData.sessionId,
  userMessage:  sentimentData.userMessage,
  aiMessage,
  modelUsed,
  responseTime,
  sentiment:    sentimentData.sentimentData.sentiment,
  confidence:   sentimentData.sentimentData.confidence,
  reason:       sentimentData.sentimentData.reason,
  emotions:     sentimentData.sentimentData.emotions,
  toneUsed:     sentimentData.selectedTone.name
};

