// =============================================================
// 감정 분석 에러 처리
// LLM 오류, JSON 파싱 실패 등을 처리
// =============================================================

const error        = $input.first().json.error || {};
const errorMessage = error.message || '감정 분석 처리 중 오류가 발생했습니다.';

let statusCode = 500;
let errorCode  = 'SENTIMENT_ERROR';

if (errorMessage.startsWith('AUTH_FAILED'))     { statusCode = 401; errorCode = 'UNAUTHORIZED'; }
else if (errorMessage.startsWith('VALIDATION')) { statusCode = 400; errorCode = 'BAD_REQUEST'; }
else if (errorMessage.includes('timeout'))      { statusCode = 504; errorCode = 'GATEWAY_TIMEOUT'; }

return {
  errorResponse: JSON.stringify({
    success:   false,
    error:     errorCode,
    message:   '감정 분석 요청을 처리하는 중 오류가 발생했습니다.',
    detail:    errorMessage,
    timestamp: new Date().toISOString()
  }),
  statusCode
};
